description:
## Bug Report

Please answer these questions before submitting your issue. Thanks!

### 1. Minimal reproduce step (Required)
```sql
USE test;
DROP DATABASE IF EXISTS database38;
CREATE DATABASE database38;
USE database38;

CREATE TABLE t0(c0 FLOAT ZEROFILL NOT NULL DEFAULT 0.04620542418916285 );

CREATE OR REPLACE ALGORITHM=TEMPTABLE VIEW v82(c0) AS SELECT DISTINCT -1293187837 FROM t0;

TRUNCATE t0;

REPLACE INTO t0(c0) VALUES (0.6186362626549486);
INSERT INTO t0 VALUES (0.05757263723534567) ON DUPLICATE KEY UPDATE c0=((t0.c0)AND(t0.c0));
INSERT INTO t0 VALUES (0.7032173504722);

UPDATE t0 SET c0=t0.c0;
INSERT INTO t0(c0) VALUES (8.62163545E8);

INSERT INTO t0(c0) VALUES (1.2829581E9) ON DUPLICATE KEY UPDATE c0=']';

UPDATE t0 SET c0='0' WHERE DEFAULT(t0.c0);
INSERT INTO t0 VALUES (0.6025603453324666) ON DUPLICATE KEY UPDATE c0=CONCAT(t0.c0);
INSERT INTO t0(c0) VALUES (0.5866291294033453) ON DUPLICATE KEY UPDATE c0=t0.c0;
INSERT INTO t0(c0) VALUES (0.6886645288521922) ON DUPLICATE KEY UPDATE c0=t0.c0;

INSERT INTO t0 VALUES (0.12323627108707103);
UPDATE t0 SET c0=(CASE 2016798040 WHEN t0.c0 THEN 'XiiU3Ddq' ELSE true END );
INSERT INTO t0(c0) VALUES (0.20928406390576193);

SELECT DISTINCT t0.c0 FROM  v82 INNER JOIN t0 ON (((- (CHAR(INET6_ATON(1543385653))))) IS NOT NULL); 

(SELECT DISTINCT t0.c0 FROM  v82 LEFT JOIN t0 ON (((- (CHAR(INET6_ATON(1543385653))))) IS NOT NULL)) INTERSECT (SELECT DISTINCT t0.c0 FROM  v82 RIGHT JOIN t0 ON (((- (CHAR(INET6_ATON(1543385653))))) IS NOT NULL)); 
```
